create table dirkspzm32.edi_vda4987_text (
    document_id        varchar2(32 char) not null enable,
    pos                number(4, 0) not null enable,
    language_name_code varchar2(3 char) default 'DE' not null enable,
    desc_code          varchar2(17 char),
    text1              varchar2(256 char),
    text2              varchar2(256 char),
    text3              varchar2(256 char),
    text4              varchar2(256 char),
    text5              varchar2(256 char)
);

alter table dirkspzm32.edi_vda4987_text
    add constraint pk_edi_vda4987_text
        primary key ( document_id,
                      pos,
                      language_name_code )
            using index enable;


